1083→/// Serialize `config` to TOML and write it to the provided path.
1084→///
1085→/// For existing TOML files, this preserves user comments by merging the new
1086→/// serialized values into the current document structure before writing.
1087→pub fn save_config_to_path(path: &Path, config: &MoltisConfig) -> crate::Result<PathBuf> {
1088→    if let Some(parent) = path.parent() {
1089→        std::fs::create_dir_all(parent)?;
1090→    }
1091→    let toml_str = toml::to_string_pretty(config)
1092→        .map_err(|source| crate::Error::external("serialize config", source))?;
1093→
1094→    let is_toml_path = path
1095→        .extension()
1096→        .and_then(|ext| ext.to_str())
1097→        .is_some_and(|ext| ext.eq_ignore_ascii_case("toml"));
1098→
1099→    if is_toml_path && path.exists() {
1100→        if let Err(error) = merge_toml_preserving_comments(path, &toml_str) {
1101→            warn!(
1102→                path = %path.display(),
1103→                error = %error,
1104→                "failed to preserve TOML comments, rewriting config without comments"
1105→            );
1106→            std::fs::write(path, toml_str)?;
1107→        }
1108→    } else {
1109→        std::fs::write(path, toml_str)?;
1110→    }
1111→
1112→    debug!(path = %path.display(), "saved config");
1113→    Ok(path.to_path_buf())
1114→}
