1130→fn merge_toml_tables(current: &mut toml_edit::Table, updated: &toml_edit::Table) {
1131→    let current_keys: Vec<String> = current.iter().map(|(key, _)| key.to_string()).collect();
1132→    for key in current_keys {
1133→        if !updated.contains_key(&key) {
1134→            let _ = current.remove(&key);
1135→        }
1136→    }
1137→
1138→    for (key, updated_item) in updated.iter() {
1139→        if let Some(current_item) = current.get_mut(key) {
1140→            merge_toml_items(current_item, updated_item);
1141→        } else {
1142→            current.insert(key, updated_item.clone());
1143→        }
1144→    }
1145→}
1146→
1147→fn merge_toml_items(current: &mut toml_edit::Item, updated: &toml_edit::Item) {
1148→    match (current, updated) {
1149→        (toml_edit::Item::Table(current_table), toml_edit::Item::Table(updated_table)) => {
1150→            merge_toml_tables(current_table, updated_table);
1151→        },
1152→        (toml_edit::Item::Value(current_value), toml_edit::Item::Value(updated_value)) => {
1153→            let existing_decor = current_value.decor().clone();
1154→            *current_value = updated_value.clone();
1155→            *current_value.decor_mut() = existing_decor;
1156→        },
1157→        (current_item, updated_item) => {
1158→            *current_item = updated_item.clone();
1159→        },
1160→    }
1161→}
