#[cfg(test)]
mod test_section_ordering {
    #[test]
    fn toml_roundtrip_section_order() {
        // Simulate what happens: start with template order, serialize config, merge
        let template = r#"# Comment
[server]
port = 8080

[auth]
disabled = false

[identity]
# name = "moltis"

[user]
# name = "test"

[providers]

[chat]
model = "gpt-4"
"#;

        // What toml::to_string_pretty would produce for the struct in field order
        let serialized = r#"[server]
port = 8080

[auth]
disabled = false

[chat]
model = "gpt-4"

[providers]
"#;
        // Note: [identity] and [user] are missing because all fields are None
        // Note: order is different (chat before providers in struct)

        let mut current_doc = template.parse::<toml_edit::DocumentMut>().unwrap();
        let updated_doc = serialized.parse::<toml_edit::DocumentMut>().unwrap();

        // Apply the same merge logic
        merge_tables(current_doc.as_table_mut(), updated_doc.as_table());

        let result = current_doc.to_string();
        println!("RESULT:\n{result}");

        // Check if [identity] and [user] survived
        assert!(result.contains("[identity]"), "identity section was removed!");
        assert!(result.contains("[user]"), "user section was removed!");

        // Check ordering: server should come before auth
        let server_pos = result.find("[server]").unwrap();
        let auth_pos = result.find("[auth]").unwrap();
        assert!(server_pos < auth_pos, "server should come before auth");
    }

    fn merge_tables(current: &mut toml_edit::Table, updated: &toml_edit::Table) {
        let current_keys: Vec<String> = current.iter().map(|(key, _)| key.to_string()).collect();
        for key in current_keys {
            if !updated.contains_key(&key) {
                let _ = current.remove(&key);
            }
        }
        for (key, updated_item) in updated.iter() {
            if let Some(current_item) = current.get_mut(key) {
                merge_items(current_item, updated_item);
            } else {
                current.insert(key, updated_item.clone());
            }
        }
    }

    fn merge_items(current: &mut toml_edit::Item, updated: &toml_edit::Item) {
        match (current, updated) {
            (toml_edit::Item::Table(ct), toml_edit::Item::Table(ut)) => merge_tables(ct, ut),
            (toml_edit::Item::Value(cv), toml_edit::Item::Value(uv)) => {
                let d = cv.decor().clone();
                *cv = uv.clone();
                *cv.decor_mut() = d;
            }
            (ci, ui) => *ci = ui.clone(),
        }
    }
}
