    /// Reproduce GH-684: sections swap places after web UI save.
    #[test]
    fn merge_toml_preserves_section_order() {
        // Template order: server, auth, identity, user, providers, chat
        let original = r#"# Config
[server]
port = 8080

[auth]
disabled = false

[identity]
# name = "moltis"

[user]
# name = "test"

[providers]

[chat]
model = "gpt-4"
"#;

        // Simulate toml::to_string_pretty output (struct field order, missing empty sections)
        let serialized = r#"[server]
port = 8080

[providers]

[chat]
model = "gpt-4"

[auth]
disabled = false
"#;
        // Note: identity and user are MISSING (all Option fields are None)
        // Note: auth is AFTER chat (struct field order differs from template)

        let mut current_doc = original.parse::<toml_edit::DocumentMut>().unwrap();
        let updated_doc = serialized.parse::<toml_edit::DocumentMut>().unwrap();

        merge_toml_tables(current_doc.as_table_mut(), updated_doc.as_table());

        let result = current_doc.to_string();
        eprintln!("MERGE RESULT:\n{result}");

        // identity and user should be REMOVED (not in updated) - this is the bug
        // They existed in the original with comments but get deleted
        let has_identity = result.contains("[identity]");
        let has_user = result.contains("[user]");
        eprintln!("identity present: {has_identity}, user present: {has_user}");

        // Check that existing sections maintain original order
        let server_pos = result.find("[server]").unwrap();
        let auth_pos = result.find("[auth]").unwrap();
        assert!(
            server_pos < auth_pos,
            "server should come before auth (original order preserved)"
        );
    }

    /// Verify what toml::to_string_pretty does with a default MoltisConfig
    #[test]
    fn default_config_serialization_sections() {
        let config = MoltisConfig::default();
        let toml_str = toml::to_string_pretty(&config).unwrap();
        eprintln!("DEFAULT CONFIG SECTIONS:");
        for line in toml_str.lines() {
            if line.starts_with('[') {
                eprintln!("  {line}");
            }
        }
        // Check which sections are present/missing
        let has_identity = toml_str.contains("[identity]");
        let has_user = toml_str.contains("[user]");
        eprintln!("identity present: {has_identity}, user present: {has_user}");
    }
}

