            load_workspace_markdown_with_source(main_path, WorkspaceMarkdownSource::AgentWorkspace)
        {
            return Some(memory);
        }
        return load_workspace_markdown_with_source(
            memory_path(),
            WorkspaceMarkdownSource::RootWorkspace,
