    /// GH-684: verify section order after full roundtrip with real template.
    #[test]
    fn gh684_template_section_order_preserved_after_save() {
        let dir = tempfile::tempdir().expect("tempdir");
        let path = dir.path().join("moltis.toml");
        let template = crate::template::default_config_template(18789);
        std::fs::write(&path, &template).expect("write template");

        // Extract section order from template
        let template_sections: Vec<String> = template
            .lines()
            .filter(|l| l.starts_with('['))
            .map(|l| l.to_string())
            .collect();
        eprintln!("TEMPLATE section order ({} sections):", template_sections.len());
        for s in &template_sections {
            eprintln!("  {s}");
        }

        // Load, modify, save — simulating a web UI setting change
        let raw = std::fs::read_to_string(&path).expect("read");
        let mut config: MoltisConfig = parse_config(&raw, &path).expect("parse");
        config.auth.disabled = true;
        config.server.http_request_logs = true;

        save_config_to_path(&path, &config).expect("save config");

        let saved = std::fs::read_to_string(&path).expect("read saved");
        let saved_sections: Vec<String> = saved
            .lines()
            .filter(|l| l.starts_with('['))
            .map(|l| l.to_string())
            .collect();
        eprintln!("\nSAVED section order ({} sections):", saved_sections.len());
        for s in &saved_sections {
            eprintln!("  {s}");
        }

        // Every template section must still exist in the saved file
        for ts in &template_sections {
            assert!(
                saved_sections.contains(ts),
                "template section {ts} missing from saved file"
            );
        }

        // Template sections must maintain their relative order
        let template_positions: Vec<usize> = template_sections
            .iter()
            .map(|ts| {
                saved_sections
                    .iter()
                    .position(|ss| ss == ts)
                    .unwrap_or_else(|| panic!("section {ts} not found in saved"))
            })
            .collect();
        for window in template_positions.windows(2) {
            assert!(
                window[0] < window[1],
                "template sections swapped: saved position {} >= {} \
                 (sections around index {})",
                window[0],
                window[1],
                window[0],
            );
        }
    }

    /// GH-684: minimal reproduction of sub-table interleaving.
    #[test]
    fn gh684_subtable_interleaving_minimal() {
        let original = r#"[server]
port = 8080

[metrics]
enabled = false

[channels]
offered = ["telegram"]

[memory]
enabled = true
"#;

        // Simulate toml::to_string_pretty which adds sub-tables
        let updated = r#"[server]
port = 8080

[metrics]
enabled = false

[metrics.labels]
env = "prod"

[channels]
offered = ["telegram"]

[channels.telegram]
token = "abc"

[channels.whatsapp]
token = "xyz"

[memory]
enabled = true
"#;

        let mut current_doc = original.parse::<toml_edit::DocumentMut>().unwrap();
        let updated_doc = updated.parse::<toml_edit::DocumentMut>().unwrap();

        merge_toml_tables(current_doc.as_table_mut(), updated_doc.as_table());

        let result = current_doc.to_string();
        eprintln!("MINIMAL INTERLEAVE TEST RESULT:\n{result}");

        // Check: channels.telegram should come AFTER [channels], not before
        let channels_pos = result.find("[channels]").unwrap();
        let telegram_pos = result.find("[channels.telegram]");
        eprintln!(
            "channels at byte {channels_pos}, telegram at byte {:?}",
            telegram_pos
        );
        if let Some(tp) = telegram_pos {
            if tp < channels_pos {
                eprintln!("BUG: [channels.telegram] appears BEFORE [channels]!");
            }
        }

        // Check: metrics.labels should come after [metrics]
        let metrics_pos = result.find("[metrics]").unwrap();
        let labels_pos = result.find("[metrics.labels]");
        eprintln!(
            "metrics at byte {metrics_pos}, labels at byte {:?}",
            labels_pos
        );
        if let Some(lp) = labels_pos {
            if lp < metrics_pos {
                eprintln!("BUG: [metrics.labels] appears BEFORE [metrics]!");
            }
        }
    }

    /// GH-684: verify serialized section order from toml::to_string_pretty
    #[test]
    fn gh684_serialized_section_order() {
        let config = MoltisConfig::default();
        let toml_str = toml::to_string_pretty(&config).unwrap();
        let sections: Vec<&str> = toml_str
            .lines()
            .filter(|l| l.starts_with('['))
            .collect();
        eprintln!("SERIALIZED section order ({} sections):", sections.len());
        for s in &sections {
            eprintln!("  {s}");
        }

        // template order for top-level sections
        let template_order = [
            "[server]",
            "[auth]",
            "[graphql]",
            "[tls]",
            "[identity]",
            "[user]",
            "[providers]",
            "[chat]",
            "[tools]",
            "[skills]",
            "[mcp]",
            "[metrics]",
            "[heartbeat]",
            "[failover]",
        ];

        // Check if serialized order matches template for these top-level sections
        let mut mismatches = vec![];
        for pair in template_order.windows(2) {
            let a_pos = sections.iter().position(|s| *s == pair[0]);
            let b_pos = sections.iter().position(|s| *s == pair[1]);
            if let (Some(a), Some(b)) = (a_pos, b_pos) {
                if a > b {
                    mismatches.push(format!(
                        "{} (pos {a}) should come before {} (pos {b})",
                        pair[0], pair[1]
                    ));
                }
            }
        }
        if !mismatches.is_empty() {
            eprintln!("\nSERIALIZED ORDER MISMATCHES vs template:");
            for m in &mismatches {
                eprintln!("  {m}");
            }
        }
    }
}

