    fn apply_env_overrides_multiple() {
        let vars = vec![
            ("MOLTIS_AUTH__DISABLED".into(), "true".into()),
            ("MOLTIS_TOOLS__AGENT_TIMEOUT_SECS".into(), "300".into()),
            ("MOLTIS_TAILSCALE__MODE".into(), "funnel".into()),
